// slug → fileId в Google Drive (PDF гайда) + красивое название.
// Замени FILE_ID_* на реальные ID файлов в Google Drive.
const MAP = {
  'relocation-english':   { fileId: 'FILE_ID_RELOCATION', title: 'Английский для релокации',                fileName: 'relocation-english.pdf' },
  'english-for-parents':  { fileId: 'FILE_ID_PARENTS',    title: 'Английский для родителей',                fileName: 'english-for-parents.pdf' },
  'medical-english':      { fileId: 'FILE_ID_MEDICAL',    title: 'Английский для медиков',                  fileName: 'medical-english.pdf' },
  'it-interview-english': { fileId: 'FILE_ID_IT',         title: 'English for Tech Interviews',             fileName: 'it-interview-english.pdf' },
  'ai-first-english':     { fileId: 'FILE_ID_AI',         title: 'AI-first English for Tech Stars',         fileName: 'ai-first-english.pdf' },
  'legal-english':        { fileId: 'FILE_ID_LEGAL',      title: 'Legal English: Contracts & Compliance',   fileName: 'legal-english.pdf' },
  'logistics-english':    { fileId: 'FILE_ID_LOGISTICS',  title: 'Logistic English',                        fileName: 'logistics-english.pdf' },
  'leadership-english':   { fileId: 'FILE_ID_LEADERSHIP', title: 'The language of Power — English for Leaders', fileName: 'leadership-english.pdf' }
};

const body = items[0].json.body || items[0].json;
const object = (body && body.object) || {};
const metadata = object.metadata || {};
const slug = (metadata.guide_slug || '').toString();
const email = (metadata.email || (object.receipt && object.receipt.customer && object.receipt.customer.email) || '').toString().trim();
const paymentId = (object.id || '').toString();
const amount = object.amount || {};

if (!slug || !MAP[slug]) {
  throw new Error('Unknown or missing guide_slug in metadata: ' + slug);
}
if (!email) {
  throw new Error('Missing email in metadata');
}

const product = MAP[slug];

return [{
  json: {
    guide_slug: slug,
    email,
    payment_id: paymentId,
    amount_value: amount.value,
    amount_currency: amount.currency,
    title: product.title,
    fileId: product.fileId,
    fileName: product.fileName
  }
}];
